+        let (w2, _, _) = race2_outcomes(RaceWinner::Second, o2b, o2a);
+
+        // Both should have the same winner value
+        if let (Outcome::Ok(v1), Outcome::Ok(v2)) = (w1, w2) {
+            assert_eq!(v1, v2);
+        } else {
+            panic!("Expected both winners to be Ok");
+        }
+    }
