+
+        // Race 1: properly drained
+        let race1 = oracle.on_race_start(region(0), vec![task(1), task(2)], t(0));
+        oracle.on_task_complete(task(1), t(50));
+        oracle.on_task_complete(task(2), t(60));
+        oracle.on_race_complete(race1, task(1), t(100));
