+    ///
+    /// This checks only poll and cost quotas, not deadline (which requires current time).
+    #[must_use]
+    pub const fn is_exhausted(&self) -> bool {
+        self.poll_quota == 0 || matches!(self.cost_quota, Some(0))
+    }
